"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[324],{2258:e=>{e.exports=JSON.parse('{"functions":[{"name":"Puppeteer","desc":"Server side function. Begins controlled replication of `voxel` to the clients according to the Puppeteer settings.\\n\\nReturns the index of the new Puppet in the [Shatterbox.Puppets] sparse array. If the voxel was already a puppet, then the puppetID of that voxel is returned.\\n\\nWhen the part stops moving, it will become anchored to allow for a larger number of ground debris while still having good motion.\\n\\nIt is safe to un-anchor these parts again in your destruction effects to have them start replicating again, they will still anchor themselves when they stop moving.","params":[{"name":"voxel","desc":"","lua_type":"Part"}],"returns":[{"desc":"","lua_type":"number"}],"function_type":"static","realm":["Server"],"source":{"line":2386,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"IsPuppet","desc":"Returns the ID of the passed in part, only if it is a member of the [Shatterbox.Puppets] sparse array.\\n\\nOn the client side, this will always be false because the client sided puppets are indestructible.","params":[{"name":"voxel","desc":"","lua_type":"Part"}],"returns":[{"desc":"","lua_type":"number?"}],"function_type":"static","realm":["Server"],"source":{"line":2467,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"GetPuppetAsync","desc":"A function that will wait for a Puppet with a given id to exist in [Shatterbox.Puppets], and return it if it was found.","params":[{"name":"puppetID","desc":"","lua_type":"number"},{"name":"waitCount","desc":"The number of Heartbeats to wait. Defaults to 10.","lua_type":"number?"}],"returns":[{"desc":"","lua_type":"Part?\\r\\n"}],"function_type":"static","realm":["Client"],"source":{"line":2553,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"Destroy","desc":"Queues voxel destruction to be performed around the hitbox according to the `params` supplied.","params":[{"name":"params","desc":"","lua_type":"DestructionParameters | Hitbox"}],"returns":[],"function_type":"static","source":{"line":2593,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"ImaginaryVoxels","desc":"Instantly performs voxel destruction around the hitbox according to the `params` supplied.\\n\\nReturns the imaginary voxels to be created as well as any existing debris encountered.\\n\\nThese are to be instantiated using [Shatterbox.InstantiateImaginaryVoxel].\\n\\n:::warning\\nIf you use SkipEncapsulatedVoxels, the #length of the imaginary voxels array will show up as larger than it really is.\\n\\nThis is to give the same functionality as [OnDestructCompleted voxelCount](/api/Shatterbox#OnDestructCompleted) without the need for a third return value.\\n\\nUse `ipairs` or generalized iteration to iterate over this array.\\n:::","params":[{"name":"params","desc":"","lua_type":"DestructionParameters | Hitbox"}],"returns":[{"desc":"","lua_type":"{ImaginaryVoxel}"},{"desc":"","lua_type":"{BasePart}"}],"function_type":"static","source":{"line":2631,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"InstantiateImaginaryVoxel","desc":"Returns a created voxel using the supplied `ImaginaryVoxel`.\\n\\nWill automatically parent the voxel to the original parent of the group.\\n\\nWill also automatically give the voxel the `\\"ShatterboxDebris\\"` tag unless you pass in `doNotGiveDebrisTag`.\\n\\n:::tip\\nYou would want to pass in `doNotGiveDebrisTag` if you\'re going to use the static function [Shatterbox.OnVoxelDestruct] to use/extend an existing effect.\\n:::","params":[{"name":"ImaginaryVoxel","desc":"","lua_type":"ImaginaryVoxel"},{"name":"doNotGiveDebrisTag","desc":"","lua_type":"boolean?"}],"returns":[{"desc":"","lua_type":"Part\\r\\n"}],"function_type":"static","source":{"line":2666,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"ResetArea","desc":"Resets an area. Currently only supports Box shaped areas.\\n\\nDoes not revert the ownership of parts with Client-Server enabled.","params":[{"name":"area","desc":"","lua_type":"Part|ImaginaryPart"}],"returns":[],"function_type":"static","source":{"line":2692,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"Reset","desc":"Resets all modified parts and re-allocates system queues/maps.\\n\\nIf `doNotRevertOwnership` is `true` with Client-Server enabled, the clients do not delete their owned map parts.","params":[{"name":"doNotRevertOwnership","desc":"","lua_type":"boolean?"}],"returns":[],"function_type":"static","source":{"line":2742,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"CreateHitbox","desc":"Creates a Hitbox object which can be used in place of the destruction functions, and has additional functionality. (like VoxBreaker moveable hitbox)\\n\\nIf you use ExcludePlayersReplication, that will be cleared after every destruction automatically, for convenience.","params":[],"returns":[{"desc":"","lua_type":"Hitbox"}],"function_type":"static","source":{"line":2994,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"GetOriginalPart","desc":"Returns the original part that is associated with this DirtyGroupID.\\n\\nThis part is never destroyed, just has its parent set to `nil`.","params":[{"name":"DirtyGroupID","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"BasePart\\r\\n"}],"function_type":"static","source":{"line":3009,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"VoxelDistanceVector","desc":"Takes a `point` and converts it to the voxel space distance relative to `voxel`.\\n\\nThis is a vector which tells you how many voxels away `point` is on each local axis, as fractional quantities.\\n\\nIt is possible for an axis to be less than one, but never negative.\\n\\n:::tip\\nSee `Shatterbox/effects/Server/MappingVoxelSpace` for an example on how to use VoxelDistanceVector\\n:::","params":[{"name":"voxel","desc":"","lua_type":"Part|ImaginaryPart"},{"name":"point","desc":"","lua_type":"Vector3"}],"returns":[{"desc":"","lua_type":"Vector3\\r\\n"}],"function_type":"static","source":{"line":3029,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"VoxelCountVector","desc":"Returns a vector that tells you how many voxels (relative to `voxel`) a box determined by `boxSize` has on each local axis, as fractional quantities.\\n\\nIt is *not* possible for an axis to be less than one, because there is always at least one voxel on every axis.\\n\\n:::tip\\nSee `Shatterbox/effects/Server/MappingVoxelSpace` for an example on how to use VoxelCountVector\\n:::","params":[{"name":"voxel","desc":"","lua_type":"Part|ImaginaryPart"},{"name":"boxSize","desc":"","lua_type":"Vector3"}],"returns":[{"desc":"","lua_type":"Vector3\\r\\n"}],"function_type":"static","source":{"line":3045,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"RegisterOnVoxelDestruct","desc":"Will register the given callback to the given name.\\n\\nIf you call this function on the server side, you are creating a server-side effect. Vice-versa for registering on the client side.\\n\\nConsider using `Shatterbox/effects` modules for effect definitions.\\n\\n:::warning\\nRegister any given effect only once, you are free to use it by name in scripts other than the one it is defined in.\\n:::","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"callback","desc":"","lua_type":"OnVoxelDestructType"}],"returns":[],"function_type":"static","source":{"line":3064,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"Cleanup","desc":"Properly returns a tuple of parts to the cache if ObjectCache is enabled. Parts not from the cache or if ObjectCache is disabled are directly destroyed.\\n\\n:::danger\\nIf you have ObjectCache enabled, you **must** use this function to destroy map parts and voxels created by this library.\\n:::","params":[{"name":"...","desc":"","lua_type":"BasePart"}],"returns":[],"function_type":"static","source":{"line":3079,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"OnVoxelDestruct","desc":"A function to manually call a registered OnVoxelDestruct effect.\\n\\n:::tip\\nThis can be used as a way to constructively build on top of any existing effects, saving you time.\\n\\n#### Example\\n```lua\\n-- BumpyFloorBreakWalls but it makes every voxel black\\nShatterbox.RegisterOnVoxelDestruct(\\"ExtendingAnEffect\\", function(voxel, info)\\n\\tvoxel.Color = Color3.new()\\n\\tShatterbox.OnVoxelDestruct(\\"BumpyFloorBreakWalls\\", voxel, info)\\nend)\\n```\\n:::","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"voxel","desc":"","lua_type":"Part"},{"name":"info","desc":"","lua_type":"VoxelInfo"}],"returns":[],"function_type":"static","source":{"line":3108,"path":"src/shared/Shatterbox/Main.luau"}}],"properties":[{"name":"Puppets","desc":"A sparse array that holds information for every puppet in existence.\\n\\n### Example\\n\\nServer:\\n```lua\\nShatterbox.RegisterOnVoxelDestruct(\\"Fall\\", function(voxel, info)\\n\\t-- voxels try to fly away from the center of the destruction hitbox\\n\\tvoxel.AssemblyLinearVelocity = (voxel.Position - info.CuttingPart.CFrame.Position).Unit * 30\\n\\n\\t-- create map to store the Puppet IDs generated or affected by this destruction if it doesnt exist\\n\\tlocal PuppetIDs = info.UserData.PuppetIDs \\n\\tif not PuppetIDs then\\n\\t\\tPuppetIDs = {}\\n\\t\\tinfo.UserData.PuppetIDs = PuppetIDs\\n\\tend\\n\\n\\t-- if the voxel was already a puppet, Puppeteer returns the ID of that puppet.\\n\\t-- Puppeteer also automatically unanchors voxels.\\n\\tlocal puppetID = Shatterbox.Puppeteer(voxel)\\n\\tPuppetIDs[puppetID] = true\\nend)\\n\\n\\nlocal hb = Shatterbox.CreateHitbox()\\nhb.Size = Vector3.one * 16\\nhb.OnVoxelDestruct = \\"Fall\\"\\n\\nhb.OnDestructCompleted = function()\\n\\tlocal PuppetIDs = hb.UserData.PuppetIDs\\n\\n\\tif PuppetIDs then\\n\\t\\t-- Tell clients to do stuff with the found and created puppets.\\n\\t\\tSignalClientPuppetVFX:FireAllClients(PuppetIDs)\\n\\n\\t\\t-- clear the map after each destruction\\n\\t\\thb.UserData.PuppetIDs = {}\\n\\tend\\nend\\n```\\n\\nClient:\\n```lua\\nSignalClientPuppetVFX.OnClientEvent:Connect(function(voxelIDs)\\n\\tlocal Puppets = Shatterbox.Puppets\\n\\n\\tfor id in pairs(voxelIDs) do\\n\\t\\tlocal PuppetPart = Shatterbox.GetPuppetAsync(id)\\n\\t\\tif not PuppetPart then continue end\\n\\n\\t\\t-- do whatever you want with the client side puppet part\\n\\tend\\nend)\\n```","lua_type":"{PuppetDataType}","source":{"line":2544,"path":"src/shared/Shatterbox/Main.luau"}}],"types":[{"name":"OnDestructCompleted","desc":"A function that defines behavior to happen after a destruction is finished processing.\\n\\n### voxelCount\\n\\nA number that dictates how many voxels this destruction destroyed. This number is identical whether or not [DestructionParameters.SkipEncapsulatedVoxels] is true.\\n\\n### affectedIDs\\n\\nAn array that contains every DirtyGroupID encountered during this destruction.\\n\\nUse this to obtain information such as the materials this destruction encountered.\\n\\n```lua\\nhb.OnDestructCompleted = function(count, affectedIDs)\\n\\tlocal materials = {}\\n\\n\\tfor DirtyGroupID in pairs(affectedIDs) do\\n\\t\\tlocal original = Shatterbox.GetOriginalPart(DirtyGroupID)\\n\\t\\tmaterials[original.Material] = true\\n\\tend\\n\\n\\tfor material in pairs(materials) do\\n\\t\\t-- do something once for every material the destruction encountered\\n\\tend\\nend\\n```","lua_type":"(voxelCount : number, affectedIDs : { [string] : boolean }) -> ()","source":{"line":2287,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"OnVoxelDestructType","desc":"A function that is run for every voxel the destruction encounters.\\n\\nsee [DestructionParameters.OnVoxelDestruct] for a brief explanation on how to use it.","lua_type":"(voxel : Part, info : VoxelInfo) -> ()","source":{"line":2297,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"VoxelInfo","desc":"A table that contains information about the destroyed voxel\\n\\n### DirtyGroupID\\n\\nThe ID of the dirty group this voxel is a part of.\\n\\nA dirty group is a group of parts that all originated from the same part.\\n\\n### CuttingPart\\n\\nThe state of the hitbox as it was when the destruction was queued.\\n\\n### IsEdge\\n\\nWhether or not this voxel lies along the edge of the destruction.\\n\\n### IsAlreadyDebris\\n\\nWhether or not this voxel was already debris before this destruction destroyed it again.\\n\\n### UserData\\n\\nUser supplied information to use in the OnVoxelDestruct effect.\\n\\nEquivalent to [DestructionParameters.UserData].","fields":[{"name":"DirtyGroupID","lua_type":"string","desc":""},{"name":"CuttingPart","lua_type":"ImaginaryPart","desc":""},{"name":"IsEdge","lua_type":"boolean","desc":""},{"name":"IsAlreadyDebris","lua_type":"boolean","desc":""},{"name":"UserData","lua_type":"{any}","desc":""}],"source":{"line":2336,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"ImaginaryPart","desc":"A table that represents a physical object","fields":[{"name":"CFrame","lua_type":"CFrame","desc":""},{"name":"Size","lua_type":"Vector3","desc":""},{"name":"Shape","lua_type":"PartType","desc":""}],"source":{"line":2348,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"ImaginaryVoxel","desc":"Represents a voxel that might be created.\\n\\nThese are to be instantiated using [Shatterbox.InstantiateImaginaryVoxel]\\n\\nSee [Shatterbox.VoxelInfo] for an explanation on these properties.","fields":[{"name":"CFrame","lua_type":"CFrame","desc":""},{"name":"Size","lua_type":"Vector3","desc":""},{"name":"Shape","lua_type":"PartType","desc":""},{"name":"DirtyGroupID","lua_type":"string","desc":""},{"name":"IsEdge","lua_type":"boolean","desc":""},{"name":"UserData","lua_type":"{any}","desc":""}],"source":{"line":2368,"path":"src/shared/Shatterbox/Main.luau"}},{"name":"PuppetDataType","desc":"An array that holds information about a given Puppet.\\n\\nOn the client side, only [1] the Puppet Part exists. On the server side, I highly suggest you do not touch [2], [3], or [4].","fields":[{"name":"1","lua_type":"Part","desc":"The puppet voxel part."},{"name":"2","lua_type":"(doNotSignal : boolean?) -> ()","desc":"Function that properly destroys the voxel. I will be changing this in the future, don\'t worry."},{"name":"3","lua_type":"RBXScriptSignal","desc":"Connection that listens for the Destroying event on the voxel. Doesn\'t exist if ObjectCache is enabled."},{"name":"4","lua_type":"number","desc":"Timeout until this voxel becomes anchored"}],"source":{"line":2484,"path":"src/shared/Shatterbox/Main.luau"}}],"name":"Shatterbox","desc":"","source":{"line":112,"path":"src/shared/Shatterbox/Main.luau"}}')}}]);